1	export type Cell = [number, number];
2	
3	const isNeighbor = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
4	  (ax !== bx || ay !== by) && Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
5	
6	const liveNeighborCount = (cell: Cell, liveCells: Cell[]): number =>
7	  liveCells.filter((other) => isNeighbor(cell, other)).length;
8	
9	const survives = (cell: Cell, liveCells: Cell[]): boolean =>
10	  liveNeighborCount(cell, liveCells) === 2;
11	
12	const isReborn = (cell: Cell, liveCells: Cell[]): boolean =>
13	  liveNeighborCount(cell, liveCells) === 3;
14	
15	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
16	
17	const neighborsOf = ([x, y]: Cell): Cell[] => [
18	  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
19	  [x - 1, y    ],             [x + 1, y    ],
20	  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
21	];
22	
23	const deadNeighborsOf = (liveCells: Cell[]): Cell[] => {
24	  const liveKeys = new Set(liveCells.map(cellKey));
25	  const deadByKey = new Map<string, Cell>();
26	  for (const live of liveCells) {
27	    for (const neighbor of neighborsOf(live)) {
28	      const key = cellKey(neighbor);
29	      if (!liveKeys.has(key) && !deadByKey.has(key)) {
30	        deadByKey.set(key, neighbor);
31	      }
32	    }
33	  }
34	  return [...deadByKey.values()];
35	};
36	
37	export const nextGeneration = (liveCells: Cell[]): Cell[] => [
38	  ...liveCells.filter((cell) => survives(cell, liveCells)),
39	  ...deadNeighborsOf(liveCells).filter((cell) => isReborn(cell, liveCells)),
40	];
