4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell with no neighbors dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("a live cell with 2 live neighbors survives", () => {
15	    // Three cells in a row: the middle cell has 2 neighbors
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("a live cell with more than 3 live neighbors dies (overpopulation)", () => {
20	    // Center cell (1,1) has 4 live neighbors (N, S, E, W) → dies
21	    const result = nextGeneration([
22	      [1, 0], [0, 1], [1, 1], [2, 1], [1, 2],
23	    ]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
27	    // L-tromino: (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors.
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("a block (2x2) is a still life and remains unchanged", () => {
32	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
33	    const result = nextGeneration(block);
34	    expect(result).toHaveLength(4);
35	    expect(result).toEqual(expect.arrayContaining(block));
